2	import { render, screen, within } from '@testing-library/react';
3	import userEvent from '@testing-library/user-event';
4	import { TableName, TableNameSchema } from 'prisma/zod/schemas';
5	import { vi } from 'vitest';
6	
7	import { Props as PlayerLinkProps } from '@/components/PlayerLink/PlayerLink';
8	import { RecordsTable } from '@/components/RecordsTable/RecordsTable';
9	import { Props as TableScoreProps } from '@/components/TableScore/TableScore';
10	import { config } from '@/lib/config';
11	import { extractMockProps, Wrapper } from '@/tests/components/lib/common';
12	import { createMockPlayerRecordData, defaultPlayerRecordDataList } from '@/tests/mocks/data/playerRecordData';
13	import { PlayerRecordDataType } from '@/types';
14	
15	vi.mock('@/components/PlayerLink/PlayerLink');
16	vi.mock('@/components/TableScore/TableScore');
17	
18	const getFirstDataRowCells = () => {
19	    const [, tbody] = screen.getAllByRole('rowgroup');
20	    const [firstRow] = within(tbody).getAllByRole('row');
21	    return within(firstRow).getAllByRole('cell');
22	};
23	
24	// Collapses JSX-formatting whitespace (newlines/indentation between
25	// expressions) so assertions compare against the meaningful text only.
26	const normalizeText = (text: string | null) => (text ?? '').replace(/\s+/g, ' ').trim();
27	
28	const getRankColumnValues = () => {
29	    const [, tbody] = screen.getAllByRole('rowgroup');
30	    const rows = within(tbody).getAllByRole('row');
31	    return rows.map((row) => normalizeText(within(row).getAllByRole('cell')[0].textContent));
32	};
33	
34	const getRankCell = (rowIndex: number) => {
35	    const [, tbody] = screen.getAllByRole('rowgroup');
36	    const rows = within(tbody).getAllByRole('row');
37	    return within(rows[rowIndex]).getAllByRole('cell')[0];
38	};
39	
40	// Text nodes sitting directly in the cell are what a sighted user sees;
41	// text inside a child element (the VisuallyHidden span) is accessible-only.
42	const getRankCellVisibleText = (cell: HTMLElement) =>
43	    normalizeText(
44	        Array.from(cell.childNodes)
45	            .filter((node) => node.nodeType === Node.TEXT_NODE)
46	            .map((node) => node.textContent)
47	            .join(''),
48	    );
49	
50	describe('RecordsTable', () => {
51	    it('renders qualified table with player records', () => {
52	        render(
53	            <Wrapper>
54	                <RecordsTable
55	                    table={TableNameSchema.enum.points}
56	                    year={2024}
57	                    records={defaultPlayerRecordDataList}
58	                />
59	            </Wrapper>,
60	        );
61	
62	        {
63	            const props = extractMockProps<PlayerLinkProps>('PlayerLink');
64	            expect(props.length).toBe(20);
65	            expect(props[0].player.name).toEqual("Gary Player");
66	        }
67	
68	        {
69	            const props = extractMockProps<TableScoreProps>('TableScore');
70	            expect(props.length).toBe(20);
71	            expect(props[0].table).toEqual(TableNameSchema.enum.points);
72	            expect(props[0].playerRecord.playerId).toEqual(12);
73	        }
74	    });
75	
76	    describe.each([
77	        [TableNameSchema.enum.points, 'rankPoints', 1, 'Points'],
78	        [TableNameSchema.enum.averages, 'rankAverages', 2, 'Average'],
79	        [TableNameSchema.enum.stalwart, 'rankStalwart', 3, 'Games Played'],
80	        [TableNameSchema.enum.speedy, 'rankSpeedy', 4, 'Average Response Time (hh:mm:ss)'],
81	        [TableNameSchema.enum.pub, 'rankPub', 5, 'Pub Score'],
82	    ] satisfies [TableName, keyof PlayerRecordDataType, number, string][])(
83	        'when table is "%s"',
84	        (table, rankField, expectedRank, expectedHeading) => {
85	            it(`renders the ${rankField} value in the rank column`, () => {
86	                render(
87	                    <Wrapper>
88	                        <RecordsTable
89	                            table={table}
90	                            year={2024}
