160	        it('applies the same treatment to a three-way tie', () => {
161	            render(
162	                <Wrapper>
163	                    <RecordsTable
164	                        table={TableNameSchema.enum.points}
165	                        year={2024}
166	                        records={[
167	                            createMockPlayerRecordData({ id: 1, rankPoints: 1 }),
168	                            createMockPlayerRecordData({ id: 2, rankPoints: 1 }),
169	                            createMockPlayerRecordData({ id: 3, rankPoints: 1 }),
170	                        ]}
171	                    />
172	                </Wrapper>,
173	            );
174	
175	            expect(getRankColumnValues()).toEqual(['1', '1', '1']);
176	
177	            expect(getRankCellVisibleText(getRankCell(0))).toBe('1');
178	            expect(getRankCellVisibleText(getRankCell(1))).toBe('');
179	            expect(getRankCellVisibleText(getRankCell(2))).toBe('');
180	        });
181	    });
182	
183	    describe('missing ranks', () => {
184	        it('renders "-" independently for each consecutive missing rank, without treating them as a tie', () => {
185	            render(
186	                <Wrapper>
187	                    <RecordsTable
188	                        table={TableNameSchema.enum.points}
189	                        year={2024}
190	                        records={[
191	                            createMockPlayerRecordData({ id: 1, rankPoints: undefined }),
192	                            createMockPlayerRecordData({ id: 2, rankPoints: null }),
193	                            createMockPlayerRecordData({ id: 3, rankPoints: 1 }),
194	                        ]}
195	                    />
196	                </Wrapper>,
197	            );
198	
199	            expect(getRankColumnValues()).toEqual(['-', '-', '1']);
200	
201	            // Every "-" is fully visible content, not a blanked continuation
202	            // row with an accessible-only value hiding behind it.
203	            expect(getRankCellVisibleText(getRankCell(0))).toBe('-');
204	            expect(getRankCellVisibleText(getRankCell(1))).toBe('-');
205	            expect(getRankCellVisibleText(getRankCell(2))).toBe('1');
206	        });
207	
208	        it('does not treat a real rank as tied with a preceding missing rank', () => {
209	            render(
210	                <Wrapper>
211	                    <RecordsTable
212	                        table={TableNameSchema.enum.points}
213	                        year={2024}
214	                        records={[
215	                            createMockPlayerRecordData({ id: 1, rankPoints: undefined }),
216	                            createMockPlayerRecordData({ id: 2, rankPoints: 2 }),
217	                            createMockPlayerRecordData({ id: 3, rankPoints: 2 }),
218	                        ]}
219	                    />
220	                </Wrapper>,
221	            );
222	
223	            expect(getRankColumnValues()).toEqual(['-', '2', '2']);
224	            expect(getRankCellVisibleText(getRankCell(1))).toBe('2');
225	            expect(getRankCellVisibleText(getRankCell(2))).toBe('');
226	        });
227	    });
228	
229	    describe('show more / show less', () => {
230	        const untiedRecords = Array.from(
231	            { length: config.recordsTableVisibleRows + 5 },
232	            (_, index) => createMockPlayerRecordData({ id: index + 1, rankPoints: index + 1 }),
233	        );
234	
235	        it('renders only the configured number of rows, with a "show more" toggle', () => {
236	            render(
237	                <Wrapper>
238	                    <RecordsTable
239	                        table={TableNameSchema.enum.points}
240	                        year={2024}
241	                        records={untiedRecords}
242	                    />
243	                </Wrapper>,
244	            );
245	
246	            expect(extractMockProps<PlayerLinkProps>('PlayerLink')).toHaveLength(
247	                config.recordsTableVisibleRows,
248	            );
249	            expect(screen.getByRole('button', { name: 'Show 5 more' })).toBeInTheDocument();
250	        });
251	
252	        it('reveals the remaining rows when the toggle is clicked, then hides them again', async () => {
253	            const user = userEvent.setup();
254	            render(
255	                <Wrapper>
256	                    <RecordsTable
257	                        table={TableNameSchema.enum.points}
258	                        year={2024}
259	                        records={untiedRecords}
260	                    />
261	                </Wrapper>,
262	            );
263	
264	            await user.click(screen.getByRole('button', { name: 'Show 5 more' }));
265	
266	            expect(extractMockProps<PlayerLinkProps>('PlayerLink')).toHaveLength(untiedRecords.length);
267	            const showLess = screen.getByRole('button', { name: 'Show less' });
268	
269	            await user.click(showLess);
270	
271	            expect(extractMockProps<PlayerLinkProps>('PlayerLink')).toHaveLength(
272	                config.recordsTableVisibleRows,
273	            );
274	        });
275	
276	        it('does not render a toggle when all rows already fit', () => {
277	            render(
278	                <Wrapper>
279	                    <RecordsTable
280	                        table={TableNameSchema.enum.points}
281	                        year={2024}
282	                        records={defaultPlayerRecordDataList}
283	                    />
284	                </Wrapper>,
285	            );
286	
287	            expect(screen.queryByRole('button', { name: /show/i })).not.toBeInTheDocument();
288	        });
289	
290	        it('does not split a tie straddling the cutoff', () => {
291	            const tiedAcrossCutoff = untiedRecords.map((record, index) =>
292	                index === config.recordsTableVisibleRows ?
293	                    { ...record, rankPoints: config.recordsTableVisibleRows } :
294	                    record,
295	            );
296	
297	            render(
298	                <Wrapper>
299	                    <RecordsTable
300	                        table={TableNameSchema.enum.points}
301	                        year={2024}
302	                        records={tiedAcrossCutoff}
303	                    />
304	                </Wrapper>,
